let currentCategory='';let currentSort='newest';let currentPage=1;let totalPages=1;function authHeaders(){const token=localStorage.getItem('flower-token');return token ?{'Authorization':'Bearer '+token,'Content-Type':'application/json'}:{'Content-Type':'application/json'};}function userLoggedIn(){return typeof window.isLoggedIn==='function' ? window.isLoggedIn():!!localStorage.getItem('flower-token');}function formatNumber(n){if(n >=1000)return(n/1000).toFixed(1)+'K';return String(n);}function timeAgo(dateStr){const date=new Date(dateStr);const now=new Date();const diff=Math.floor((now-date)/1000);if(diff < 60)return 'just now';if(diff < 3600)return Math.floor(diff/60)+'m ago';if(diff < 86400)return Math.floor(diff/3600)+'h ago';if(diff < 604800)return Math.floor(diff/86400)+'d ago';return date.toLocaleDateString();}function getAvatarHtml(avatar,name){if(!avatar)return(name || '?')[0].toUpperCase();if(avatar.startsWith('/')|| avatar.startsWith('http')){return `<img src="${escapeHtml(avatar)}" alt="${escapeHtml(name || '')}">`;}return avatar;}function isExpertRole(role){return ['FLORIST','INSTRUCTOR','ADMIN','SUPERADMIN'].includes((role || '').toUpperCase());}async function initDiscussionsPage(){if(!userLoggedIn()){const myBtn=document.getElementById('myDiscBtn');if(myBtn)myBtn.style.display='none';}await loadCategories();await loadDiscussions();loadStats();loadTopContributors();document.getElementById('discSearchBtn').addEventListener('click',()=>{currentPage=1;loadDiscussions();});document.getElementById('discSearch').addEventListener('keydown',(e)=>{if(e.key==='Enter'){currentPage=1;loadDiscussions();}});document.getElementById('categoryTabs').addEventListener('click',(e)=>{const tab=e.target.closest('.category-tab');if(!tab)return;document.querySelectorAll('.category-tab').forEach(t=> t.classList.remove('active'));tab.classList.add('active');currentCategory=tab.dataset.slug || '';currentPage=1;loadDiscussions();});document.getElementById('sortTabs').addEventListener('click',(e)=>{const tab=e.target.closest('.sort-tab');if(!tab)return;document.querySelectorAll('.sort-tab').forEach(t=> t.classList.remove('active'));tab.classList.add('active');currentSort=tab.dataset.sort;currentPage=1;loadDiscussions();});}async function loadCategories(){let categories;try{const res=await fetch('/api/discussions/categories');categories=await res.json();}catch{categories=[];}const tabs=document.getElementById('categoryTabs');tabs.innerHTML=`<button class="category-tab active" data-slug="">All</button>`+categories.map(c=> `<button class="category-tab" data-slug="${escapeHtml(c.slug || '')}">${c.icon || ''}${escapeHtml(c.name)}</button>`).join('');}async function loadDiscussions(){const search=document.getElementById('discSearch').value.trim();const params=new URLSearchParams({sort:currentSort,page:currentPage,limit:20});if(currentCategory)params.set('category',currentCategory);if(search)params.set('search',search);let data;try{const res=await fetch(`/api/discussions?${params}`);data=await res.json();}catch{data={discussions:[],total:0,pages:1};}const list=document.getElementById('discussionList');if(!data.discussions || !data.discussions.length){list.innerHTML=`<div class="empty-state"><i class="bi bi-chat-dots"></i><h3>No discussions found</h3><p>Be the first to start a conversation!</p></div>`;document.getElementById('pagination').innerHTML='';return;}totalPages=data.pages || 1;list.innerHTML=data.discussions.map(d=> ` <div class="disc-card${d.is_pinned ? ' pinned':''}${d.is_solved ? ' solved':''}" onclick="window.location.href='discussion-detail.html?id=${escapeHtml(String(d.id))}'"> <div class="disc-avatar">${getAvatarHtml(d.author_avatar,d.author_name)}</div> <div class="disc-body"> <div class="disc-title"> ${d.is_pinned ? '<span class="pinned-badge"><i class="bi bi-pin-fill"></i> Pinned</span>':''}${d.is_solved ? '<span class="solved-badge"><i class="bi bi-check-lg"></i> Solved</span>':''}${escapeHtml(d.title)}</div> <div class="disc-meta"> by <strong>${escapeHtml(d.author_name || 'Anonymous')}</strong> ${isExpertRole(d.author_role)? '<span class="expert-badge">Expert</span>':''}· ${escapeHtml(d.category_name || 'General')}· ${timeAgo(d.created_at)}</div> <div class="disc-excerpt">${escapeHtml(d.excerpt || '')}</div> <div class="disc-tags"> <span class="disc-tag">${escapeHtml(d.category_name || 'General')}</span> </div> </div> ${d.image ? `<div class="disc-image-preview"><img src="${escapeHtml(d.image)}" alt="" loading="lazy"></div>`:''}<div class="disc-stats"> <div class="disc-stat"><i class="bi bi-arrow-up"></i> ${formatNumber(d.vote_count || 0)}</div> <div class="disc-stat"><i class="bi bi-chat-dots"></i> ${d.reply_count || 0}</div> <div class="disc-stat"><i class="bi bi-eye"></i> ${formatNumber(d.views || 0)}</div> </div> </div> `).join('');renderPagination();}function renderPagination(){const el=document.getElementById('pagination');if(totalPages <=1){el.innerHTML='';return;}let html='';if(currentPage > 1)html+=`<button class="page-btn" onclick="goToPage(${currentPage-1})"><i class="bi bi-chevron-left"></i></button>`;for(let i=1;i <=totalPages;i++){if(totalPages > 7 && i > 3 && i < totalPages-2 && Math.abs(i-currentPage)> 1){if(i===4 || i===totalPages-3)html+=`<span style="padding:0.4rem 0.3rem;color:var(--text-muted)">...</span>`;continue;}html+=`<button class="page-btn${i===currentPage ? ' active':''}" onclick="goToPage(${i})">${i}</button>`;}if(currentPage < totalPages)html+=`<button class="page-btn" onclick="goToPage(${currentPage+1})"><i class="bi bi-chevron-right"></i></button>`;el.innerHTML=html;}function goToPage(page){currentPage=page;loadDiscussions();window.scrollTo({top:0,behavior:'smooth'});}async function loadStats(){try{const res=await fetch('/api/discussions/stats/overview');const stats=await res.json();document.getElementById('statMembers').textContent=formatNumber(stats.members || 0);document.getElementById('statDiscussions').textContent=formatNumber(stats.discussions || 0);document.getElementById('statReplies').textContent=formatNumber(stats.replies || 0);}catch{}}async function loadTopContributors(){try{const res=await fetch('/api/discussions/top/contributors');const contributors=await res.json();const el=document.getElementById('topContributors');if(!contributors.length){el.innerHTML='<li style="color:var(--text-muted);font-size:0.85rem;">No contributors yet</li>';return;}el.innerHTML=contributors.slice(0,5).map((c,i)=> ` <li> <span class="contributor-rank">${i+1}</span> <div class="contributor-avatar">${getAvatarHtml(c.profile_image,c.name)}</div> <span>${escapeHtml(c.name)}</span> <span class="contributor-score">${(c.discussions || 0)+(c.replies || 0)}posts</span> </li> `).join('');}catch{}}async function initDiscussionDetail(){const params=new URLSearchParams(window.location.search);const id=params.get('id');if(!id){document.getElementById('discussionContent').innerHTML='<div class="empty-state"><h3>Discussion not found</h3></div>';return;}let discussion;try{const res=await fetch(`/api/discussions/${id}`,{headers:authHeaders()});if(!res.ok)throw new Error('Not found');discussion=await res.json();}catch{document.getElementById('discussionContent').innerHTML='<div class="empty-state"><i class="bi bi-chat-dots"></i><h3>Discussion not found</h3><p>This discussion may have been removed.</p></div>';return;}document.title=`${discussion.title}| Flower Ecosystem`;const imagesHtml=(discussion.images || []).length ? `<div class="disc-detail-images">${discussion.images.map(url=> `<img src="${escapeHtml(url)}" alt="Discussion image" loading="lazy">`).join('')}</div>`:'';const userVote=discussion.userVote;document.getElementById('discussionContent').innerHTML=` <div class="disc-detail-card"> <div class="disc-detail-header"> <div class="disc-detail-avatar">${getAvatarHtml(discussion.author_avatar,discussion.author_name)}</div> <div class="disc-detail-meta" style="flex:1;"> <h1>${escapeHtml(discussion.title)}</h1> <div class="author-info"> by <span class="author-name">${escapeHtml(discussion.author_name || 'Anonymous')}</span> ${isExpertRole(discussion.author_role)? '<span class="expert-badge">Expert</span>':''}· <span class="disc-tag" style="font-size:0.75rem;">${escapeHtml(discussion.category_name || 'General')}</span> · ${timeAgo(discussion.created_at)}</div> </div> </div> <div class="disc-detail-content">${escapeHtml(discussion.content)}</div> ${imagesHtml}<div class="disc-detail-footer"> <div class="disc-detail-stats"> <span><i class="bi bi-eye"></i> ${formatNumber(discussion.views || 0)}views</span> <span><i class="bi bi-chat-dots"></i> ${(discussion.comments || []).length}replies</span> <span><i class="bi bi-clock"></i> ${timeAgo(discussion.created_at)}</span> </div> <div class="vote-controls"> <button class="vote-btn${userVote==='up' ? ' active':''}" onclick="voteDiscussion('${discussion.id}','up')" title="Upvote"><i class="bi bi-arrow-up"></i></button> <span class="vote-count" id="discVoteCount">${discussion.vote_count || 0}</span> <button class="vote-btn${userVote==='down' ? ' active':''}" onclick="voteDiscussion('${discussion.id}','down')" title="Downvote"><i class="bi bi-arrow-down"></i></button> </div> </div> </div> `;renderComments(discussion);renderReplyBox(discussion);loadRelatedDiscussions(discussion.category_slug,discussion.id);}function renderComments(discussion){const section=document.getElementById('commentsSection');const comments=discussion.comments || [];const bestAnswer=comments.find(c=> c.is_best_answer);const regularComments=comments.filter(c=> !c.is_best_answer);const sorted=bestAnswer ? [bestAnswer,...regularComments]:regularComments;let html=`<div class="comments-header"><h2 style="font-size:1.1rem;">${comments.length}${comments.length===1 ? 'Reply':'Replies'}</h2></div>`;if(!comments.length){html+='<p style="color:var(--text-light);font-size:0.9rem;margin-bottom:1rem;">No replies yet. Be the first to respond!</p>';}html+=sorted.map(c=> ` <div class="comment-card${c.is_best_answer ? ' best-answer':''}"> <div class="comment-avatar">${getAvatarHtml(c.author_avatar,c.author_name)}</div> <div class="comment-body"> <div class="comment-meta"> <span class="author-name">${escapeHtml(c.author_name || 'Anonymous')}</span> ${isExpertRole(c.author_role)? '<span class="expert-badge">Expert</span>':''}${c.is_best_answer ? '<span class="best-answer-badge"><i class="bi bi-check-circle-fill"></i> Best Answer</span>':''}<span>${timeAgo(c.created_at)}</span> </div> <div class="comment-content">${escapeHtml(c.content)}</div> <div class="comment-actions"> <button onclick="voteComment('${c.id}','up')" title="Helpful"><i class="bi bi-hand-thumbs-up"></i> Helpful</button> ${discussion.author_id===(getCurrentUserId())|| ['ADMIN','SUPERADMIN'].includes((getCurrentUserRole()|| '').toUpperCase())? `<button onclick="markBestAnswer('${discussion.id}','${c.id}')" title="Mark as best answer"><i class="bi bi-check-circle"></i> Best Answer</button>`:''}${c.author_id===getCurrentUserId()|| ['ADMIN','SUPERADMIN','MODERATOR'].includes((getCurrentUserRole()|| '').toUpperCase())? `<button onclick="deleteComment('${c.id}','${discussion.id}')" title="Delete"><i class="bi bi-trash"></i></button>`:''}</div> </div> <div class="vote-controls" style="flex-direction:column;"> <button class="vote-btn" onclick="voteComment('${c.id}','up')" style="width:28px;height:28px;"><i class="bi bi-arrow-up"></i></button> <span class="vote-count" style="font-size:0.8rem;">${c.vote_count || 0}</span> <button class="vote-btn" onclick="voteComment('${c.id}','down')" style="width:28px;height:28px;"><i class="bi bi-arrow-down"></i></button> </div> </div> `).join('');section.innerHTML=html;}function renderReplyBox(discussion){const section=document.getElementById('commentsSection');if(userLoggedIn()){section.innerHTML+=` <div class="reply-box"> <h3 style="font-size:0.95rem;margin-bottom:0.75rem;">Write a Reply</h3> <textarea id="replyContent" placeholder="Share your thoughts or advice..."></textarea> <div class="reply-box-footer"> <span style="font-size:0.8rem;color:var(--text-muted);">Be respectful and helpful</span> <button class="btn btn-primary btn-sm" onclick="submitReply('${discussion.id}')"> <i class="bi bi-send"></i> Submit Reply </button> </div> </div> `;}else{section.innerHTML+=` <div class="reply-box login-prompt"> <p><a href="#" onclick="openAuthModal('login');return false;">Sign in</a> to join the discussion and reply to this thread.</p> </div> `;}}function getCurrentUserId(){try{const token=localStorage.getItem('flower-token');if(token){const payload=JSON.parse(atob(token.split('.')[1]));return payload.id;}}catch{}const user=JSON.parse(localStorage.getItem('flower-auth')|| 'null');return user?.id || null;}function getCurrentUserRole(){try{const token=localStorage.getItem('flower-token');if(token){const payload=JSON.parse(atob(token.split('.')[1]));return payload.role;}}catch{}const user=JSON.parse(localStorage.getItem('flower-auth')|| 'null');return user?.role || null;}async function submitReply(discussionId){const content=document.getElementById('replyContent').value.trim();if(!content)return;try{const res=await fetch(`/api/discussions/${discussionId}/comments`,{method:'POST',headers:authHeaders(),body:JSON.stringify({content})});if(!res.ok)throw new Error('Failed');window.location.reload();}catch(err){alert('Failed to post reply. Please try again.');}}async function voteDiscussion(id,voteType){if(!userLoggedIn()){openAuthModal('login');return;}try{const res=await fetch(`/api/discussions/${id}/vote`,{method:'POST',headers:authHeaders(),body:JSON.stringify({vote_type:voteType})});const data=await res.json();document.getElementById('discVoteCount').textContent=data.vote_count;document.querySelectorAll('.vote-controls .vote-btn').forEach(btn=> btn.classList.remove('active'));}catch{}}async function voteComment(commentId,voteType){if(!userLoggedIn()){openAuthModal('login');return;}try{await fetch(`/api/discussions/comments/${commentId}/vote`,{method:'POST',headers:authHeaders(),body:JSON.stringify({vote_type:voteType})});}catch{}}async function markBestAnswer(discussionId,commentId){if(!confirm('Mark this as the best answer?'))return;try{await fetch(`/api/discussions/${discussionId}`,{method:'PUT',headers:authHeaders(),body:JSON.stringify({best_answer_id:commentId})});window.location.reload();}catch{}}async function deleteComment(commentId,discussionId){if(!confirm('Delete this comment?'))return;try{await fetch(`/api/discussions/comments/${commentId}`,{method:'DELETE',headers:authHeaders()});window.location.reload();}catch{}}async function loadRelatedDiscussions(categorySlug,currentId){if(!categorySlug)return;try{const res=await fetch(`/api/discussions?category=${categorySlug}&limit=5`);const data=await res.json();const related=(data.discussions || []).filter(d=> d.id !==currentId).slice(0,5);const el=document.getElementById('relatedList');if(!related.length){document.getElementById('relatedDiscussions').style.display='none';return;}el.innerHTML=related.map(d=> ` <li><a href="discussion-detail.html?id=${escapeHtml(String(d.id))}">${escapeHtml(d.title)}</a></li> `).join('');}catch{}}let uploadedFiles=[];async function initCreateDiscussion(){if(!userLoggedIn()){openAuthModal('login');return;}const categorySelect=document.getElementById('discCategory');try{const res=await fetch('/api/discussions/categories');const categories=await res.json();categories.forEach(c=>{const opt=document.createElement('option');opt.value=c.id;opt.textContent=`${c.icon || ''}${c.name}`;categorySelect.appendChild(opt);});}catch{}document.getElementById('discTitle').addEventListener('input',(e)=>{document.getElementById('titleCount').textContent=e.target.value.length;});const uploadArea=document.getElementById('uploadArea');const fileInput=document.getElementById('fileInput');uploadArea.addEventListener('click',()=> fileInput.click());uploadArea.addEventListener('dragover',(e)=>{e.preventDefault();uploadArea.classList.add('dragover');});uploadArea.addEventListener('dragleave',()=> uploadArea.classList.remove('dragover'));uploadArea.addEventListener('drop',(e)=>{e.preventDefault();uploadArea.classList.remove('dragover');handleFiles(e.dataTransfer.files);});fileInput.addEventListener('change',(e)=> handleFiles(e.target.files));document.getElementById('createDiscussionForm').addEventListener('submit',async(e)=>{e.preventDefault();const title=document.getElementById('discTitle').value.trim();const category_id=document.getElementById('discCategory').value;const content=document.getElementById('discContent').value.trim();const errorMsg=document.getElementById('errorMsg');const successMsg=document.getElementById('successMsg');const submitBtn=document.getElementById('submitBtn');errorMsg.style.display='none';successMsg.style.display='none';if(!title || !content){errorMsg.textContent='Title and content are required';errorMsg.style.display='block';return;}submitBtn.disabled=true;submitBtn.innerHTML='<span class="auth-spinner" style="margin-right:0.5rem;"></span> Posting...';const formData=new FormData();formData.append('title',title);formData.append('content',content);if(category_id)formData.append('category_id',category_id);uploadedFiles.forEach(f=> formData.append('images',f));try{const token=localStorage.getItem('flower-token');const res=await fetch('/api/discussions',{method:'POST',headers:token ?{'Authorization':'Bearer '+token}:{},body:formData});if(!res.ok){const err=await res.json();throw new Error(err.error || 'Failed');}const data=await res.json();window.location.href=`discussion-detail.html?id=${data.id}`;}catch(err){errorMsg.textContent=err.message || 'Failed to create discussion';errorMsg.style.display='block';submitBtn.disabled=false;submitBtn.innerHTML='<i class="bi bi-send"></i> Post Discussion';}});}function handleFiles(files){const grid=document.getElementById('previewGrid');Array.from(files).forEach(file=>{if(file.size > 5*1024*1024)return;if(!file.type.startsWith('image/'))return;if(uploadedFiles.length >=5)return;uploadedFiles.push(file);const reader=new FileReader();reader.onload=(e)=>{const idx=uploadedFiles.length-1;const div=document.createElement('div');div.className='preview-item';div.innerHTML=`<img src="${e.target.result}" alt="Preview"><button class="preview-remove" onclick="removeFile(${idx},this)"><i class="bi bi-x"></i></button>`;grid.appendChild(div);};reader.readAsDataURL(file);});}function removeFile(idx,btn){uploadedFiles.splice(idx,1);btn.parentElement.remove();}